import { useRouter } from 'next/navigation';

const currentYear = new Date().getFullYear();
const years = Array.from({ length: 5 }, (_, i) => currentYear - i);
const months = [
    { value: -1, label: 'Todos' },
    { value: 0, label: 'Enero' }, { value: 1, label: 'Febrero' }, { value: 2, label: 'Marzo' },
    { value: 3, label: 'Abril' }, { value: 4, label: 'Mayo' }, { value: 5, label: 'Junio' },
    { value: 6, label: 'Julio' }, { value: 7, label: 'Agosto' }, { value: 8, label: 'Septiembre' },
    { value: 9, label: 'Octubre' }, { value: 10, label: 'Noviembre' }, { value: 11, label: 'Diciembre' }
];

export default function ClientesPage() {
  const { toast } = useToast();
  const router = useRouter();
  const [clients, setClients] = useState<Client[]>([]);
  const [advisors, setAdvisors] = useState<Advisor[]>([]);
  const [entities, setEntities] = useState<Entity[]>([]);

  const [isClientFormOpen, setIsClientFormOpen] = useState(false);
  const [isAdvisorManagerOpen, setIsAdvisorManagerOpen] = useState(false);
  const [isEntityManagerOpen, setIsEntityManagerOpen] = useState(false);

  const [editingClient, setEditingClient] = useState<Client | null>(null);

  // --- FILTER STATE ---
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('Todos');
  const [advisorFilter, setAdvisorFilter] = useState('Todos');
  const [docTypeFilter, setDocTypeFilter] = useState('Todos');
  const [monthFilter, setMonthFilter] = useState(-1);
  const [yearFilter, setYearFilter] = useState(currentYear);


  useEffect(() => {
    try {
      const savedClients = localStorage.getItem('clients');
      if (savedClients) setClients(JSON.parse(savedClients));

      const savedAdvisors = localStorage.getItem('advisors');
      if (savedAdvisors) {
          setAdvisors(JSON.parse(savedAdvisors));
      } else {
        const defaultAdvisors: Advisor[] = [
          { id: '1', name: "Asesor 1", commissionType: 'percentage', commissionValue: 10 },
        ];
        setAdvisors(defaultAdvisors);
        localStorage.setItem('advisors', JSON.stringify(defaultAdvisors));
      }

      const savedEntities = localStorage.getItem('entities');
      if(savedEntities) setEntities(JSON.parse(savedEntities));

    } catch (error) {
      console.error("Failed to load data from localStorage", error);
    }
  }, []);

  useEffect(() => {
    try {
        localStorage.setItem('clients', JSON.stringify(clients));
    } catch (error) {
        console.error("Failed to save clients to localStorage", error);
    }
  }, [clients]);

  useEffect(() => {
    try {
        if(advisors.length > 0) {
            localStorage.setItem('advisors', JSON.stringify(advisors));
        }
    } catch (error) {
        console.error("Failed to save advisors to localStorage", error);
    }
  }, [advisors]);

  useEffect(() => {
    try {
      localStorage.setItem('entities', JSON.stringify(entities));
    } catch (error) {
      console.error("Failed to save entities to localStorage", error);
    }
  }, [entities]);

  const handleSaveClient = (saveData: { client: Client, addMultiple?: (allClients: Client[], allAdvisors: Advisor[]) => { updatedClients: Client[], updatedAdvisors: Advisor[] } }) => {
    if (saveData.addMultiple) {
        setClients(prevClients => {
            const { updatedClients, updatedAdvisors } = saveData.addMultiple!(prevClients, advisors);
            if (updatedAdvisors.length > advisors.length) {
                setAdvisors(updatedAdvisors);
            }
            return updatedClients;
        });
    } else {
        setClients(prevClients => {
          const existingIndex = prevClients.findIndex(c => c.id === saveData.client.id);
          if (existingIndex > -1) {
            const updatedClients = [...prevClients];
            updatedClients[existingIndex] = saveData.client;
            return updatedClients;
          } else {
            return [...prevClients, saveData.client];
          }
        });
    }
    setIsClientFormOpen(false);
  };

  const handleEditClient = (client: Client) => {
      setEditingClient(client);
      setIsClientFormOpen(true);
  }

  const handleOpenNewClientForm = () => {
    setEditingClient(null);
    setIsClientFormOpen(true);
  };

  const handleDeleteClient = (clientId: string) => {
      setClients(prev => prev.filter(c => c.id !== clientId));
      toast({ title: 'Cliente eliminado', description: 'El cliente ha sido eliminado de la base de datos.' });
  }

  const handleSaveAdvisors = (updatedAdvisors: Advisor[]) => {
      setAdvisors(updatedAdvisors);
      setIsAdvisorManagerOpen(false);
  };

  const handleSaveEntities = (updatedEntities: Entity[]) => {
    setEntities(updatedEntities);
    setIsEntityManagerOpen(false);
  }

  const handleGenerateInvoice = (clientId: string) => {
    router.push(`/tools/documentos?clientId=${clientId}`);
  };

  const filteredClients = useMemo(() => {
    return clients.filter(client => {
      const entryDate = new Date(client.entryDate);
      const searchMatch = searchTerm.trim() === '' || 
        client.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        client.documentId.includes(searchTerm);

      const statusMatch = statusFilter === 'Todos' || client.serviceStatus === statusFilter;
      const advisorMatch = advisorFilter === 'Todos' || client.assignedAdvisor === advisorFilter;
      const docTypeMatch = docTypeFilter === 'Todos' || client.documentType === docTypeFilter;
      const monthMatch = monthFilter === -1 || entryDate.getMonth() === monthFilter;
      const yearMatch = entryDate.getFullYear() === yearFilter;

      return searchMatch && statusMatch && advisorMatch && docTypeMatch && monthMatch && yearMatch;
    });
  }, [clients, searchTerm, statusFilter, advisorFilter, docTypeFilter, monthFilter, yearFilter]);

  const resetFilters = () => {
      setSearchTerm('');
      setStatusFilter('Todos');
      setAdvisorFilter('Todos');
      setDocTypeFilter('Todos');
      setMonthFilter(-1);
      setYearFilter(currentYear);
  };

  return (
    <div className="space-y-8">
      <Link href="/servicios" className="inline-flex items-center text-sm text-primary hover:underline mb-4">
        <ArrowLeft className="mr-2 h-4 w-4" />
        Volver a Servicios
      </Link>

      <section className="text-center">
        <h1 className="text-4xl font-bold tracking-tight text-primary">Gestión de Clientes</h1>
        <p className="mt-4 max-w-2xl mx-auto text-lg text-muted-foreground">
          Administra tu base de datos de clientes, asesores y entidades de trámite.
        </p>
      </section>

       <Card>
        <CardHeader>
            <div className="flex justify-between items-center">
                <CardTitle>Controles y Filtros</CardTitle>
                 <div className="flex flex-wrap gap-2">
                    <Button variant="outline" onClick={() => setIsAdvisorManagerOpen(true)}>
                        <UserCog className="mr-2 h-4 w-4" /> Gestionar Asesores
                    </Button>
                    <Button variant="outline" onClick={() => setIsEntityManagerOpen(true)}>
                        <Building className="mr-2 h-4 w-4" /> Gestionar Entidades
                    </Button>
                    <Button onClick={handleOpenNewClientForm}>
                        <PlusCircle className="mr-2 h-4 w-4" /> Añadir Cliente
                    </Button>
                </div>
            </div>
            <CardDescription>Usa los filtros para refinar tu búsqueda en la base de datos de clientes.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
                <div className="relative col-span-full lg:col-span-2">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                    <Input
                    type="text"
                    placeholder="Buscar cliente por nombre o documento..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 w-full"
                    />
                </div>
                 <Select value={statusFilter} onValueChange={setStatusFilter}>
                    <SelectTrigger><SelectValue placeholder="Estado..." /></SelectTrigger>
                    <SelectContent>
                        <SelectItem value="Todos">Todos los Estados</SelectItem>
                        {serviceStatuses.map(status => (
                        <SelectItem key={status} value={status}>{status}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>
                 <Select value={advisorFilter} onValueChange={setAdvisorFilter}>
                    <SelectTrigger><SelectValue placeholder="Asesor..." /></SelectTrigger>
                    <SelectContent>
                        <SelectItem value="Todos">Todos los Asesores</SelectItem>
                        {advisors.map(advisor => (
                        <SelectItem key={advisor.id} value={advisor.name}>{advisor.name}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>
                 <Select value={docTypeFilter} onValueChange={setDocTypeFilter}>
                    <SelectTrigger><SelectValue placeholder="Tipo Doc..." /></SelectTrigger>
                    <SelectContent>
