import { useState, useEffect } from 'react';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useToast } from '@/hooks/use-toast';
import { PlusCircle, Trash2, Edit, Save, ExternalLink, Phone, Mail, MapPin, MessageSquare, LayoutGrid, List } from 'lucide-react';
import type { Entity, EntityContact } from '@/lib/types';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from './ui/select';
import { credentialTypes, entityContactDepartments, entityContactTypes } from '@/lib/types';
import Link from 'next/link';
import { Badge } from './ui/badge';
import { Separator } from './ui/separator';
import { Tabs, TabsList, TabsTrigger } from './ui/tabs';

const entityLinkSchema = z.object({
    id: z.string(),
    name: z.string().min(1, "El nombre del enlace es requerido."),
    url: z.string().url("URL inválida.").or(z.literal('')),
});

const entityContactSchema = z.object({
    id: z.string(),
    type: z.enum(['phone', 'whatsapp', 'email', 'location'], { required_error: "Tipo requerido." }),
    department: z.string().min(1, "Departamento requerido."),
    label: z.string().min(1, "Etiqueta requerida."),
    value: z.string().min(1, "Valor requerido."),
});

const entitySchema = z.object({
    id: z.string(),
    name: z.string().min(2, "El nombre debe tener al menos 2 caracteres."),
    type: z.string({ required_error: "Debe seleccionar un tipo de entidad." }),
    links: z.array(entityLinkSchema).optional().default([]),
    contacts: z.array(entityContactSchema).optional().default([]),
});

const managerSchema = z.object({
  entities: z.array(entitySchema),
});

type ManagerFormData = z.infer<typeof managerSchema>;

interface EntityManagerDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  onSave: (entities: Entity[]) => void;
  allEntities: Entity[];
}

const contactIcons = {
    phone: <Phone className="mr-2 h-4 w-4 text-blue-500" />,
    whatsapp: <MessageSquare className="mr-2 h-4 w-4 text-green-500" />,
    email: <Mail className="mr-2 h-4 w-4 text-red-500" />,
    location: <MapPin className="mr-2 h-4 w-4 text-purple-500" />,
};

const ContactValue = ({ contact }: { contact: EntityContact }) => {
    let href = contact.value;
    if (contact.type === 'phone') href = `tel:${contact.value}`;
    if (contact.type === 'email') href = `mailto:${contact.value}`;
    if (contact.type === 'whatsapp') href = `https://wa.me/${contact.value.replace(/\s/g, '')}`;
    if (contact.type === 'location') href = `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(contact.value)}`;

    return (
        <a href={href} target="_blank" rel="noopener noreferrer" className="hover:underline text-sm text-foreground">
            {contact.value}
        </a>
    )
};


export function EntityManagerDialog({ isOpen, onOpenChange, onSave, allEntities }: EntityManagerDialogProps) {
  const { toast } = useToast();
  const [editingId, setEditingId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'cards' | 'list'>('cards');

  const form = useForm<ManagerFormData>({
    resolver: zodResolver(managerSchema),
    defaultValues: { entities: [] },
  });

  const { control, handleSubmit, reset, getValues } = form;

  const { fields, append, remove } = useFieldArray({
    control,
    name: "entities",
  });

  useEffect(() => {
    if (isOpen) {
      reset({ entities: allEntities });
      setEditingId(null);
    }
  }, [allEntities, isOpen, reset]);

  const onSubmit = (data: ManagerFormData) => {
    onSave(data.entities);
    toast({ title: 'Entidades actualizadas', description: 'La lista de entidades ha sido guardada.' });
    onOpenChange(false);
  };

  const handleAddNew = () => {
    const newId = crypto.randomUUID();
    append({
      id: newId,
      name: '',
      type: '',
      links: [],
      contacts: [],
    });
    setEditingId(newId);
  };

  const groupedContacts = (contacts: EntityContact[] = []) => {
    return contacts.reduce((acc, contact) => {
        (acc[contact.department] = acc[contact.department] || []).push(contact);
        return acc;
    }, {} as Record<string, EntityContact[]>);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl">
        <DialogHeader>
          <DialogTitle>Gestionar Entidades</DialogTitle>
          <DialogDescription>
            Añade, edita o elimina las entidades. Los enlaces y contactos que configures estarán disponibles para acceso rápido.
          </DialogDescription>
        </DialogHeader>
        <div className="flex justify-between items-center">
            <Button type="button" variant="outline" onClick={handleAddNew}>
                <PlusCircle className="mr-2 h-4 w-4" /> Añadir Nueva Entidad
            </Button>
            <Tabs value={viewMode} onValueChange={(value) => setViewMode(value as 'cards' | 'list')}>
                <TabsList>
                    <TabsTrigger value="cards"><LayoutGrid className="mr-2 h-4 w-4" /> Tarjetas</TabsTrigger>
                    <TabsTrigger value="list" disabled><List className="mr-2 h-4 w-4" /> Lista</TabsTrigger>
                </TabsList>
            </Tabs>
        </div>
        <Form {...form}>
          <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
            <ScrollArea className="h-[60vh] p-1 pr-4">
              {viewMode === 'cards' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {fields.map((field, index) => {
                    const isEditing = editingId === field.id;
                    const currentEntity = getValues(`entities.${index}`);

                    return (
                      <div key={field.id} className="p-4 border rounded-lg space-y-4 relative bg-card h-fit">
                        {isEditing ? (
                          <EditEntityForm index={index} control={control} setEditingId={setEditingId} />
                        ) : (
                          <ViewEntityCard entity={currentEntity} onEdit={() => setEditingId(field.id)} onRemove={() => remove(index)} groupedContacts={groupedContacts} />
                        )}
                      </div>
                    )
                  })}
                </div>
              ) : (
                <div className="text-center py-10 text-muted-foreground">La vista de lista está en construcción.</div>
              )}
            </ScrollArea>


            <DialogFooter className="mt-4 pt-4 border-t">
              <Button type="button" variant="ghost" onClick={() => onOpenChange(false)}>Cancelar</Button>
              <Button type="submit">Guardar Cambios</Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}


