## 2\. Plan de Acción Técnica (Sin cambiar el flujo)

### A. Mejorar la Robustez del Hook `useCFBraindStorage`

Vamos a añadir un listener para el evento `storage`. Esto permite que si abres CFBra\!nd en dos pestañas, los cambios en una se reflejen en la otra sin recargar.

**Mejora propuesta para `hooks/useCFBraindStorage.ts`:**

```typescript
import { useState, useEffect, useCallback } from 'react';

// Evento personalizado para sincronizar pestañas/componentes
const dispatchStorageEvent = (key: string, newValue: any) => {
  window.dispatchEvent(new Event("local-storage"));
};

export function useCFBraindStorage<T>(key: string, initialValue: T): [T, (value: T | ((val: T) => T)) => void] {
  // Función para leer de manera segura
  const readValue = useCallback((): T => {
    if (typeof window === "undefined") return initialValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.warn(`Error reading localStorage key "${key}":`, error);
      return initialValue;
    }
  }, [initialValue, key]);

  const [storedValue, setStoredValue] = useState<T>(readValue);

  // Sincronizar cambios desde otras pestañas o componentes
  useEffect(() => {
    const handleStorageChange = () => {
      setStoredValue(readValue());
    };

    // Escuchar cambios nativos y personalizados
    window.addEventListener('storage', handleStorageChange);
    window.addEventListener('local-storage', handleStorageChange);

    return () => {
      window.removeEventListener('storage', handleStorageChange);
      window.removeEventListener('local-storage', handleStorageChange);
    };
  }, [readValue]);

  const setValue = (value: T | ((val: T) => T)) => {
    try {
      const valueToStore = value instanceof Function ? (value as (val: T) => T)(storedValue) : value;
      setStoredValue(valueToStore);
      if (typeof window !== "undefined") {
        window.localStorage.setItem(key, JSON.stringify(valueToStore));
        // Notificar a otros componentes que usen este mismo hook
        dispatchStorageEvent(key, valueToStore);
      }
    } catch (error) {
      console.warn(`Error setting localStorage key "${key}":`, error);
    }
  };

  return [storedValue, setValue];
}
```

