const handleSaveClient = (saveData: ClientWithMultiple) => {
    // Lógica para importación masiva (Bulk Import)
    if (saveData.addMultiple) { 
        const { updatedClients, updatedAdvisors } = saveData.addMultiple(clients, advisors); 
        setClients(updatedClients); 
        setAdvisors(updatedAdvisors); 
        toast({ title: "Importación Exitosa", description: "Se han cargado los clientes masivamente." });
    } else { 
        // Lógica Unitaria (Crear o Actualizar)
        setClients(prev => { 
            const existsIndex = prev.findIndex(c => c.id === saveData.client.id); 
            let newClients;

            if (existsIndex > -1) {
                // UPDATE: Reemplazamos manteniendo la posición
                newClients = [...prev];
                newClients[existsIndex] = { ...prev[existsIndex], ...saveData.client }; // Merge seguro
                toast({ title: "Cliente Actualizado", description: `Los datos de ${saveData.client.fullName} se han guardado.` });
            } else {
                // CREATE: Agregamos al principio
                newClients = [saveData.client, ...prev]; 
                toast({ title: "Cliente Creado", description: `${saveData.client.fullName} ha sido añadido al sistema.` });
            }
            return newClients;
        }); 
    }
    setIsClientModalOpen(false); 
    setEditingClient(null);
};
